/**
 * Seed: 30 skills × ≥6 questions (3 hard + 3 medium minimum) = 194 total.
 * Run: node backend/src/seeds/skillQuestions.js
 * Safe to re-run — skips if ≥ target count already exists per skill.
 */
const mongoose    = require('mongoose');
